limitations under the License.
*/

package value

import (
	"bytes"
	"context"
	"fmt"
	"testing"
)

// mockTransformer is a simple Transformer implementation for testing.
type mockTransformer struct {
	fromResult []byte
	toResult   []byte
	err        error
	stale      bool
	lastFrom   []byte
	lastTo     []byte
}

func (m *mockTransformer) TransformFromStorage(ctx context.Context, data []byte, dataCtx Context) ([]byte, bool, error) {
	m.lastFrom = data
	if m.err != nil {
		return nil, false, m.err
	}
	if m.fromResult != nil {
		return m.fromResult, m.stale, nil
	}
	return data, m.stale, nil
}

func (m *mockTransformer) TransformToStorage(ctx context.Context, data []byte, dataCtx Context) ([]byte, error) {
	m.lastTo = data
	if m.err != nil {
		return nil, m.err
	}
	if m.toResult != nil {
		return m.toResult, nil
	}
	return data, nil
}

// TestTransformerRoundTrip verifies that TransformToStorage followed by
// TransformFromStorage returns the original data unchanged.
func TestTransformerRoundTrip(t *testing.T) {
	cases := []struct {
		name  string
		input []byte
	}{
		{"simple value", []byte("hello world")},
		{"empty value", []byte{}},
		{"binary data", []byte{0x00, 0xff, 0xab, 0xcd}},
		{"long value", bytes.Repeat([]byte("x"), 4096)},
	}

	for _, tc := range cases {
		t.Run(tc.name, func(t *testing.T) {
			inner := &mockTransformer{}
			prefix := []byte("k8s:enc:test:")
			p := NewPrefixTransformers(nil, PrefixTransformer{
				Prefix:      prefix,
				Transformer: inner,
			})
			ctx := context.Background()
			dataCtx := DefaultContext([]byte("auth"))

			encoded, err := p.TransformToStorage(ctx, tc.input, dataCtx)
			if err != nil {
				t.Fatalf("TransformToStorage: unexpected error: %v", err)
			}
			if !bytes.HasPrefix(encoded, prefix) {
				t.Fatalf("encoded value does not start with prefix %q; got %q", prefix, encoded)
			}

			decoded, stale, err := p.TransformFromStorage(ctx, encoded, dataCtx)
			if err != nil {
				t.Fatalf("TransformFromStorage: unexpected error: %v", err)
			}
			if stale {
				t.Errorf("expected stale=false, got true")
			}
			if !bytes.Equal(decoded, tc.input) {
				t.Errorf("round-trip mismatch: want %q, got %q", tc.input, decoded)
			}
		})
	}
}

// TestDefaultContextAuthenticatedData checks that DefaultContext returns itself
// as the authenticated data byte slice.
func TestDefaultContextAuthenticatedData(t *testing.T) {
	data := []byte("some-key-info")
	ctx := DefaultContext(data)
	got := ctx.AuthenticatedData()
	if !bytes.Equal(got, data) {
		t.Errorf("AuthenticatedData: want %q, got %q", data, got)
	}
}

// TestDefaultContextNil checks that nil DefaultContext returns nil.
func TestDefaultContextNil(t *testing.T) {
	var ctx DefaultContext
	got := ctx.AuthenticatedData()
	if got != nil {
		t.Errorf("expected nil, got %q", got)
	}
}

// TestPrefixTransformerMismatch verifies that data with an unrecognized prefix
// returns the fallback error and no data.
func TestPrefixTransformerMismatch(t *testing.T) {
	sentinel := fmt.Errorf("no matching prefix")
	p := NewPrefixTransformers(sentinel,
		PrefixTransformer{Prefix: []byte("a:"), Transformer: &mockTransformer{}},
		PrefixTransformer{Prefix: []byte("b:"), Transformer: &mockTransformer{}},
	)

	out, stale, err := p.TransformFromStorage(context.Background(), []byte("unknown:data"), nil)
	if err != sentinel {
		t.Errorf("expected sentinel error, got %v", err)
	}
	if stale {
		t.Errorf("expected stale=false on error")
	}
	if out != nil {
		t.Errorf("expected nil output, got %q", out)
	}
}

// TestPrefixTransformerEmptyValue verifies that an empty input returns the
// fallback error when no prefix matches.
func TestPrefixTransformerEmptyValue(t *testing.T) {
	sentinel := fmt.Errorf("no matching prefix")
	p := NewPrefixTransformers(sentinel,
		PrefixTransformer{Prefix: []byte("enc:"), Transformer: &mockTransformer{}},
	)

	out, _, err := p.TransformFromStorage(context.Background(), []byte{}, nil)
	if err != sentinel {
		t.Errorf("expected sentinel error for empty input, got %v", err)
	}
	if out != nil {
		t.Errorf("expected nil output, got %q", out)
	}
}

// TestPrefixTransformerStaleMarking verifies that data decoded by a non-first
// transformer is returned with stale=true so it will be re-encrypted.
func TestPrefixTransformerStaleMarking(t *testing.T) {
	cases := []struct {
		name          string
		input         []byte
		expectedStale bool
	}{
		{"first transformer – not stale", []byte("new:value"), false},
		{"second transformer – stale", []byte("old:value"), true},
		{"third transformer – stale", []byte("older:value"), true},
	}

	inner1 := &mockTransformer{fromResult: []byte("plaintext")}
	inner2 := &mockTransformer{fromResult: []byte("plaintext")}
	inner3 := &mockTransformer{fromResult: []byte("plaintext")}
	p := NewPrefixTransformers(fmt.Errorf("no match"),
		PrefixTransformer{Prefix: []byte("new:"), Transformer: inner1},
		PrefixTransformer{Prefix: []byte("old:"), Transformer: inner2},
		PrefixTransformer{Prefix: []byte("older:"), Transformer: inner3},
	)

	for _, tc := range cases {
		t.Run(tc.name, func(t *testing.T) {
			_, stale, err := p.TransformFromStorage(context.Background(), tc.input, nil)
			if err != nil {
				t.Fatalf("unexpected error: %v", err)
			}
			if stale != tc.expectedStale {
				t.Errorf("stale: want %v, got %v", tc.expectedStale, stale)
			}
		})
	}
}

// TestPrefixTransformerErrorPropagation verifies that an error from an inner
// transformer is propagated to the caller.
func TestPrefixTransformerErrorPropagation(t *testing.T) {
	innerErr := fmt.Errorf("inner transformer error")
	p := NewPrefixTransformers(fmt.Errorf("no match"),
		PrefixTransformer{
			Prefix:      []byte("enc:"),
			Transformer: &mockTransformer{err: innerErr},
		},
	)

	out, stale, err := p.TransformFromStorage(context.Background(), []byte("enc:data"), nil)
	if err == nil {
		t.Errorf("expected error, got nil")
	}
	if stale {
		t.Errorf("expected stale=false on error")
	}
	if out != nil {
		t.Errorf("expected nil output on error, got %q", out)
	}
}

// TestPrefixTransformerWriteUsesFirstTransformer verifies that TransformToStorage
// always uses the first registered transformer and prepends its prefix.
func TestPrefixTransformerWriteUsesFirstTransformer(t *testing.T) {
	first := &mockTransformer{toResult: []byte("encrypted")}
	second := &mockTransformer{toResult: []byte("should-not-be-used")}

	p := NewPrefixTransformers(fmt.Errorf("no match"),
		PrefixTransformer{Prefix: []byte("first:"), Transformer: first},
		PrefixTransformer{Prefix: []byte("second:"), Transformer: second},
	)

	got, err := p.TransformToStorage(context.Background(), []byte("plaintext"), nil)
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}

	expected := []byte("first:encrypted")
	if !bytes.Equal(got, expected) {
		t.Errorf("want %q, got %q", expected, got)
	}

	if second.lastTo != nil {
		t.Errorf("second transformer should not have been called, but received %q", second.lastTo)
	}
}

// TestPrefixTransformerWriteError verifies that an error from the inner
// transformer during TransformToStorage is returned and no data is produced.
func TestPrefixTransformerWriteError(t *testing.T) {
	writeErr := fmt.Errorf("write failed")
	p := NewPrefixTransformers(fmt.Errorf("no match"),
		PrefixTransformer{
			Prefix:      []byte("enc:"),
			Transformer: &mockTransformer{err: writeErr},
		},
	)

	got, err := p.TransformToStorage(context.Background(), []byte("plaintext"), nil)
	if err != writeErr {
		t.Errorf("expected writeErr, got %v", err)
	}
	if got != nil {
		t.Errorf("expected nil output on error, got %q", got)
	}
}

// TestPrefixTransformerIdentityWithErrorFallsThrough checks the identity
// (empty prefix) special case: if the identity transformer returns an error,
// the next transformer is tried rather than aborting.
func TestPrefixTransformerIdentityWithErrorFallsThrough(t *testing.T) {
	identityErr := fmt.Errorf("not plaintext – encrypted data")
	goodResult := []byte("decrypted")

	identity := &mockTransformer{err: identityErr}
	encrypted := &mockTransformer{fromResult: goodResult}

	p := NewPrefixTransformers(fmt.Errorf("no match"),
		PrefixTransformer{Prefix: []byte{}, Transformer: identity},
		PrefixTransformer{Prefix: []byte("enc:"), Transformer: encrypted},
	)

	// Data with the "enc:" prefix should be handled by the encrypted transformer.
	out, _, err := p.TransformFromStorage(context.Background(), []byte("enc:ciphertext"), nil)
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if !bytes.Equal(out, goodResult) {
		t.Errorf("want %q, got %q", goodResult, out)
	}
}

// TestPrefixTransformerStripsPrefixBeforeInnerCall verifies that the prefix
// bytes are stripped before the inner Transformer receives the data.
func TestPrefixTransformerStripsPrefixBeforeInnerCall(t *testing.T) {
	inner := &mockTransformer{}
	prefix := []byte("k8s:enc:aescbc:v1:")
	plainPayload := []byte("secretdata")
	input := append(append([]byte{}, prefix...), plainPayload...)

	p := NewPrefixTransformers(fmt.Errorf("no match"),
		PrefixTransformer{Prefix: prefix, Transformer: inner},
	)

	_, _, err := p.TransformFromStorage(context.Background(), input, nil)
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if !bytes.Equal(inner.lastFrom, plainPayload) {
		t.Errorf("inner transformer received %q, want %q", inner.lastFrom, plainPayload)
	}
}

// TestPrefixTransformerDefaultError verifies that when no custom error is
// provided to NewPrefixTransformers, a sensible default error is used.
func TestPrefixTransformerDefaultError(t *testing.T) {
	p := NewPrefixTransformers(nil,
		PrefixTransformer{Prefix: []byte("enc:"), Transformer: &mockTransformer{}},
	)

	_, _, err := p.TransformFromStorage(context.Background(), []byte("other:data"), nil)
	if err == nil {
		t.Error("expected non-nil error for unmatched prefix with nil sentinel")
	}
}

// TestPrefixTransformerMultipleOverlappingPrefixes tests that when two
// transformers share a prefix but the first fails, the second is tried.
func TestPrefixTransformerMultipleOverlappingPrefixes(t *testing.T) {
	transformErr := fmt.Errorf("key rotation: old key failed")
	goodResult := []byte("decrypted-with-new-key")

	failing := &mockTransformer{err: transformErr}
	succeeding := &mockTransformer{fromResult: goodResult}

	sharedPrefix := []byte("k8s:enc:aescbc:v1:")

	p := NewPrefixTransformers(fmt.Errorf("no match"),
		PrefixTransformer{Prefix: sharedPrefix, Transformer: failing},
		PrefixTransformer{Prefix: sharedPrefix, Transformer: succeeding},
	)

	out, _, err := p.TransformFromStorage(context.Background(), append(sharedPrefix, []byte("ciphertext")...), nil)
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if !bytes.Equal(out, goodResult) {
		t.Errorf("want %q, got %q", goodResult, out)
	}
}

